 ==\"\"){\n	return;\n}else{\n	//alert(checked);\n	var arrTables = checked.split(\",\");\n\n	var colIndex = mygridG2.getColIndexById(\"RESULT\");\n\n	for(t=0;t<arrTables.length;t++){\n		var tableNm = arrTables[t];\n\n		//alert(tableNm);\n		//alert(\"rowid, 컬럼순번:\" + tableNm + \", \" + colIndex);\n		//불러오기\n		$.ajax({\n			type : \"GET\",\n			url : CFG_CGWEB_URL + \"/c.g/cg_cdeploy_db.php?CTL=LOADFROMGITHUB&TOKEN=\" + token + \"&TARGET_DB=\" + $(\"#G1-TAGET_DB\").val() +  + \"&DB=\" + $(\"#G1-DB\").val() + \"&TABLE=\" + tableNm ,\n			dataType: \"jsonp\",\n			privateTableNm : tableNm,\n			async: false,\n			success: function(data){\n				alog(\"   gridG2 json return----------------------\");\n\n				//alog(\"   json RTN_MSG length : \" + data.RTN_MSG.length);\n\n				mygridG2.cells(this.privateTableNm,colIndex).setValue(\"O\");\n				//alert(\"응답오케이:\" + tableNm + \", \" + colIndex);\n\n			},\n			error: function(error){\n				msgError(\"[테이블목록] Ajax http 500 error ( \" + error + \" )\",3);\n				//alog(\"[테이블목록] Ajax http 500 error ( \" + data.RTN_MSG + \" )\");\n			}\n		});\n	}\n}\'\n		,MODDT = date_format(sysdate(),\'%Y%m%d%H%i%s\')\n  	where PJTSEQ = 3 and PGMSEQ = 103 and GRPSEQ = 259 and FNCSEQ = 1312\n		','PGMINFO','20200218055200'),(1064,'/c.g/cg_pgminfo_crud3.php','j0a0af1p9kp77319mrjbjti872',NULL,NULL,'zero12a',1,'log_CG','INFO','2','POP_PGMID=','PGMINFO','20200218055201'),(1065,'/c.g/cg_pgminfo_crud3.php','j0a0af1p9kp77319mrjbjti872',NULL,NULL,'zero12a',1,'log_CG','INFO','2','POP_PGMNM=','PGMINFO','20200218055201'),(1066,'/c.g/cg_pgminfo_crud3.php','j0a0af1p9kp77319mrjbjti872',NULL,NULL,'zero12a',1,'log_CG','INFO','2','POP_PJTSEQ=','PGMINFO','20200218055201'),(1067,'/c.g/cg_pgminfo_crud3.php','j0a0af1p9kp77319mrjbjti872',NULL,NULL,'zero12a',1,'log_CG','INFO','2','to_coltype before : i','PGMINFO','20200218055201'),(1068,'/c.g/cg_pgminfo_crud3.php','j0a0af1p9kp77319mrjbjti872',NULL,NULL,'zero12a',1,'log_CG','INFO','2','to_coltype after : i','PGMINFO','20200218055201'),